    const headings = Array.from(document.querySelectorAll('h2, h3'));
    const milestonesHeading = headings.find(h => h.textContent.includes('Milestones by the billions'));

    let tableData = [];
    if (milestonesHeading) {
      let next = milestonesHeading.nextElementSibling;
      let table = null;
      while (next && !table) {
        if (next.tagName === 'TABLE') table = next;
        else table = next.querySelector('table');
        next = next.nextElementSibling;
      }

      if (!table) {
        // Try parent approach
        let section = milestonesHeading.closest('section');
        if (section) table = section.querySelector('table');
      }

      if (table) {
        const rows = Array.from(table.querySelectorAll('tr'));
