          const cells = Array.from(row.querySelectorAll('th, td'));
          return cells.map(c => c.textContent.trim().replace(/\\[.*?\\]/g, ''));
        });
        return { found: true, tableData };
      }
      return { found: false, msg: 'heading found but no table', headingText: milestonesHeading.textContent };
    }
    return { found: false, msg: 'heading not found' };
  }`
});
