import { evaluateScript } from "./servers/chrome-devtools/index.js";

const result = await evaluateScript({
  function: `() => {
    const headings = Array.from(document.querySelectorAll('h2, h3'));
    const milestonesHeading = headings.find(h => h.textContent.includes('Milestones by the billions'));

    if (!milestonesHeading) return { found: false };

    // Walk through ALL following siblings and descendants to find a table
    let el = milestonesHeading;
    let found = null;
    let steps = 0;

    // Try searching the entire section or up to 20 siblings
    let next = el.parentElement ? el.parentElement.nextElementSibling : el.nextElementSibling;
    // Actually, let's search all tables and find which one is closest after the heading
    const allTables = Array.from(document.querySelectorAll('table'));

    // Get heading position
    const headingRect = milestonesHeading.getBoundingClientRect();
    const headingTop = headingRect.top + window.scrollY;

    // Find tables after this heading
    const tablesAfter = allTables.filter(t => {
      const r = t.getBoundingClientRect();
      return r.top + window.scrollY > headingTop;
    });

    if (tablesAfter.length === 0) {
      // Try getting text around the heading
      let section = milestonesHeading.parentElement;
      let text = section ? section.innerHTML.substring(0, 500) : 'no parent';
      return { found: false, tablesOnPage: allTables.length, headingTop, text };
    }

    const table = tablesAfter[0];
    const rows = Array.from(table.querySelectorAll('tr'));
    const tableData = rows.map(row => {
      const cells = Array.from(row.querySelectorAll('th, td'));
      return cells.map(c => c.textContent.trim().replace(/\\[\\d+\\]/g, '').trim());
    });

    return { found: true, tableData };
  }`
});
console.log(result);
